  assert_false_rule(
      "import \"tests\" \
      rule test { \
        condition: \
          not tests.undefined.i \
      }",
    NULL);

  assert_true_rule(
      "import \"tests\" \
      rule test { \
        condition: \
          for any k,v in tests.struct_dict : ( \
            k == \"foo\" and v.s == \"foo\" and v.i == 1 \
          ) \
      }",
      NULL);

  assert_error(
      "import \"tests\" \
      rule test { \
        condition: \
          for any k,v in tests.integer_array : ( false ) \
      }",
