  assert_error(
      "import \"tests\" \
      rule test { \
        condition: \
          for any a,b,c in tests.struct_dict : ( false ) \
      }",
      ERROR_SYNTAX_ERROR);

  assert_error(
      "import \"tests\" \
      rule test { \
        condition: \
          for any i in tests.struct_dict : ( false ) \
      }",
      ERROR_SYNTAX_ERROR);

  assert_error(
      "import \"tests\" \
      rule test { \
        condition: \
          for any i in tests.integer_array : ( undefined_ident ) \
      }",
      ERROR_UNDEFINED_IDENTIFIER);

  assert_error(
      "import \"tests\" \
      rule test { \
        condition: \
          for any i in tests.integer_array : ( i == \"foo\" ) \
      }",
      ERROR_WRONG_TYPE);


  assert_false_rule(
      "rule test { \
        condition: \
          for any i in (0,1): ( \
            for any j in (0,1): ( \
              for any k in (0,1): ( \
                for any l in (0,1): (\
                  false \
                ) \
              ) \
            ) \
        ) \
      }",
      NULL);
}


void test_re()
